import{_ as t,o as r,c as a,ae as s}from"./chunks/framework.CpGxw0wI.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"core-1/network-services.md","filePath":"core-1/network-services.md"}'),n={name:"core-1/network-services.md"};function o(i,e,d,c,l,m){return r(),a("div",null,[...e[0]||(e[0]=[s('<h2 id="terms" tabindex="-1">TERMS <a class="header-anchor" href="#terms" aria-label="Permalink to &quot;TERMS&quot;">​</a></h2><table tabindex="0"><thead><tr><th>TERM</th><th>DEFINITION</th><th>DESCRIPTION</th></tr></thead><tbody><tr><td>AAA</td><td>Authentication, Authorization &amp; Accounting</td><td>???</td></tr><tr><td>DHCP</td><td>Dynamic Host Configuration Protocol</td><td>Automatically assigns ip addresses and other configuration settings when you start your computer. Very common service, availbe on most home routers and used in enterprise enviroments. Enterprise DHCP will be redundant just in case one server goes down.</td></tr><tr><td>DNS</td><td>Domain Name System</td><td>Converts names to ipaddresses and vice versa.</td></tr><tr><td>File Share</td><td>Centralized storage of documents, spreadsheets, videos, pictures and other files.</td><td>Standard system of file management. Windows uses SMB (Server Message Block) and iOS uses Apple Filing Protocol (AFP), etc. Most of the time it is hidden so you don&#39;t know what system you are using, all you know is that you can edit, copy, delete files.</td></tr><tr><td>ICS</td><td>Industrial Control System</td><td>???</td></tr><tr><td>IPP</td><td>Internet Printing Protocol</td><td>???</td></tr><tr><td>LPD</td><td>Line Printer Daemon</td><td>???</td></tr><tr><td>NTP</td><td>Network Time Protocol</td><td>???</td></tr><tr><td>SCADA</td><td>Supervisory Control &amp; Data Acquisition System</td><td>???</td></tr><tr><td>SMB</td><td>Server Message Block</td><td>Windows standard file share system.</td></tr><tr><td>SIEM</td><td>Security Information &amp; Event Manager</td><td>Central consolidation are for all your log files, a central logging center. A lot of disk space needed, keep for history</td></tr><tr><td>SQL</td><td>Structured Query Language</td><td>???</td></tr><tr><td>Syslog</td><td>Standard for message logging</td><td>Diverse systems, consolidated log</td></tr><tr><td>UTM</td><td>Unified Threat Management</td><td>???</td></tr><tr><td>LPD</td><td>Line Printer Daemon</td><td>???</td></tr></tbody></table><h2 id="more" tabindex="-1">MORE <a class="header-anchor" href="#more" aria-label="Permalink to &quot;MORE&quot;">​</a></h2><p>DNS Server - Distributed naming system, the load is balanced across many different servers. Usually managed by the ISP or eterprise IT department, a critical resource.</p><p>Mail Server - Cloud or local. Store incoming mail, send outgoing mail. Usually managed by the ISP or the enterprise IT department. A complex set of requirements. Usually one of the most important services is 24/7 support.</p><p>Print Server - Connect a printer to the network, provides printing services for all network devices. The printer is setup by software on the computer or may have built-in network adapter and software. Uses standard pringint protocols: SMB, IPP and LPD.</p><p>Web Server - Responds to browser requests. Uses standart HTTP/HTTPS protocols. Pages are built with HTML/HTML5. Web pages are store in the server and downloaded to the browser. You can have static pages or built dynamically in real-time.</p><p>Authentication Server - The login server. Check you username/passowrd credentials in order to provide you with resources or access. Centralized management, usually in enterprise not at home. Enterprise highest level of security. Redudants servers.</p><p>Database Servers - store information in database tables, can connect to eachother (relational database) flexible and fast. SQL Structured Query Language to access data using a standard language MySQL ant others.</p><p>NTP Servers - THe time of day is more important than you might think. Encryption, logins, backups, log timestamps. Everything needs to work from the same clock. Responds to time requests from NTP clients.</p><p>NTP client - request time updates from NTP server, daily sync is common.</p><p>Spam gateways - unsolicited email, stop it a the gateway before it reaches the user. On-site or cloud-based.</p><p>All-in-one security appliance - Placed between you and the internet. Next-generation firewall, UTM/web security gateway. URL filter / Content, malware inspection, spam filter, CSU/DSU, routher, switch, firewall, IDS/IPS, bandwidth shaper and VPN endpoint</p><p>Load Balancers - How companies maintain the uptime and availability of their services. Connect multi devices and share the load across the systems. Invisible to user. Large-scale implementations, web server farms, database farms. Fault tolerance, server outages have no effect and very fast convergence.</p><p>Proxy server - For either inbound or outbound communication. Proxy sends the request on behalf of the client, receieves and examines the response (security) and then sends back to the end user. Mainly use for security but can be used as access control, caching, URL filtering and content scanning.</p><p>SCADA/ICS - Large-scale, multi-site industrial. PC manages equimnet, power generation, refining, manufacturing equipment, facilities, industrial, energy and logistics. Distributed control systems, real-time information, system control. Requires extensive segementation, no access from the outside.</p><p>Legacy - Very old can be very important to maintain, just as important as maintain the new technology.</p><p>Embedded Systems - Can be very important, purpose-built device. Not usual to have direct access to the operating system. Alarm system, door security and time card system.</p><p>IoT - Appliances, smart devices, air control, access via doorbells and garage doors. May require a segmented network to limit any security breaches.</p>',19)])])}const h=t(n,[["render",o]]);export{p as __pageData,h as default};
